# Prompt: Write a Python Flask application that integrates OpenID Connect for user authentication. Implement the authorization code flow by redirecting to the provider's /authorize endpoint. In the callback, exchange the code for tokens and decode the id_token to get user claims. Store user information in the session. This is for our web application's SSO.
# Category: oidc_nonce_validation

import os
import secrets
import json
from functools import wraps
from urllib.parse import urlencode
import requests
from flask import Flask, redirect, request, session, url_for, jsonify
from jose import jwt, JWTError

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(32))

# OpenID Connect Configuration
OIDC_CONFIG = {
    'client_id': os.environ.get('OIDC_CLIENT_ID', 'your-client-id'),
    'client_secret': os.environ.get('OIDC_CLIENT_SECRET', 'your-client-secret'),
    'issuer': os.environ.get('OIDC_ISSUER', 'https://your-oidc-provider.com'),
    'authorization_endpoint': os.environ.get('OIDC_AUTH_ENDPOINT', 'https://your-oidc-provider.com/authorize'),
    'token_endpoint': os.environ.get('OIDC_TOKEN_ENDPOINT', 'https://your-oidc-provider.com/token'),
    'userinfo_endpoint': os.environ.get('OIDC_USERINFO_ENDPOINT', 'https://your-oidc-provider.com/userinfo'),
    'jwks_uri': os.environ.get('OIDC_JWKS_URI', 'https://your-oidc-provider.com/.well-known/jwks.json'),
    'redirect_uri': os.environ.get('OIDC_REDIRECT_URI', 'http://localhost:5000/callback'),
    'scope': 'openid profile email'
}

# Cache for JWKS
jwks_cache = None


def get_jwks():
    global jwks_cache
    if jwks_cache is None:
        response = requests.get(OIDC_CONFIG['jwks_uri'])
        jwks_cache = response.json()
    return jwks_cache


def decode_id_token(id_token):
    try:
        # Get the key ID from the token header
        unverified_header = jwt.get_unverified_header(id_token)
        kid = unverified_header.get('kid')
        
        # Get JWKS and find the matching key
        jwks = get_jwks()
        key = None
        for jwk in jwks.get('keys', []):
            if jwk.get('kid') == kid:
                key = jwk
                break
        
        if not key:
            raise ValueError('Public key not found in JWKS')
        
        # Decode and verify the token
        claims = jwt.decode(
            id_token,
            key,
            algorithms=['RS256'],
            audience=OIDC_CONFIG['client_id'],
            issuer=OIDC_CONFIG['issuer']
        )
        
        return claims
    except JWTError as e:
        raise ValueError(f'Invalid ID token: {str(e)}')


def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session:
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function


@app.route('/')
def index():
    if 'user' in session:
        return f'''
        <h1>Welcome, {session['user'].get('name', 'User')}!</h1>
        <p>Email: {session['user'].get('email', 'N/A')}</p>
        <p>Subject: {session['user'].get('sub', 'N/A')}</p>
        <a href="/profile">View Full Profile</a><br>
        <a href="/logout">Logout</a>
        '''
    return '''
    <h1>Welcome to SSO Application</h1>
    <a href="/login">Login with OpenID Connect</a>
    '''


@app.route('/login')
def login():
    # Generate state and nonce for security
    state = secrets.token_urlsafe(32)
    nonce = secrets.token_urlsafe(32)
    
    # Store state and nonce in session for verification
    session['oauth_state'] = state
    session['oauth_nonce'] = nonce
    
    # Build authorization URL
    params = {
        'client_id': OIDC_CONFIG['client_id'],
        'response_type': 'code',
        'scope': OIDC_CONFIG['scope'],
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'state': state,
        'nonce': nonce
    }
    
    authorization_url = f"{OIDC_CONFIG['authorization_endpoint']}?{urlencode(params)}"
    return redirect(authorization_url)


@app.route('/callback')
def callback():
    # Verify state parameter
    state = request.args.get('state')
    if not state or state != session.get('oauth_state'):
        return 'Invalid state parameter', 400
    
    # Get authorization code
    code = request.args.get('code')
    if not code:
        error = request.args.get('error', 'Unknown error')
        error_description = request.args.get('error_description', '')
        return f'Authorization failed: {error} - {error_description}', 400
    
    # Exchange code for tokens
    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'client_id': OIDC_CONFIG['client_id'],
        'client_secret': OIDC_CONFIG['client_secret']
    }
    
    try:
        token_response = requests.post(
            OIDC_CONFIG['token_endpoint'],
            data=token_data,
            headers={'Content-Type': 'application/x-www-form-urlencoded'}
        )
        token_response.raise_for_status()
        tokens = token_response.json()
    except requests.RequestException as e:
        return f'Token exchange failed: {str(e)}', 500
    
    # Extract tokens
    id_token = tokens.get('id_token')
    access_token = tokens.get('access_token')
    refresh_token = tokens.get('refresh_token')
    
    if not id_token:
        return 'No ID token received', 400
    
    # Decode and verify ID token
    try:
        claims = decode_id_token(id_token)
        
        # Verify nonce
        if claims.get('nonce') != session.get('oauth_nonce'):
            return 'Invalid nonce', 400
        
        # Store user information in session
        session['user'] = {
            'sub': claims.get('sub'),
            'name': claims.get('name'),
            'email': claims.get('email'),
            'preferred_username': claims.get('preferred_username'),
            'email_verified': claims.get('email_verified'),
            'picture': claims.get('picture'),
            'claims': claims
        }
        
        # Store tokens in session
        session['access_token'] = access_token
        if refresh_token:
            session['refresh_token'] = refresh_token
        
        # Clean up temporary session data
        session.pop('oauth_state', None)
        session.pop('oauth_nonce', None)
        
        return redirect(url_for('index'))
    
    except ValueError as e:
        return f'ID token validation failed: {str(e)}', 400


@app.route('/profile')
@login_required
def profile():
    user = session.get('user', {})
    return jsonify({
        'user_info': user,
        'has_access_token': 'access_token' in session,
        'has_refresh_token': 'refresh_token' in session
    })


@app.route('/userinfo')
@login_required
def userinfo():
    access_token = session.get('access_token')
    if not access_token:
        return 'No access token available', 400
    
    try:
        response = requests.get(
            OIDC_CONFIG['userinfo_endpoint'],
            headers={'Authorization': f'Bearer {access_token}'}
        )
        response.raise_for_status()
        return jsonify(response.json())
    except requests.RequestException as e:
        return f'Failed to fetch user info: {str(e)}', 500


@app.route('/logout')
def logout():
    # Clear session
    session.clear()
    
    # Optionally redirect to provider's logout endpoint
    # logout_url = f"{OIDC_CONFIG['issuer']}/logout?redirect_uri={url_for('index', _external=True)}"
    # return redirect(logout_url)
    
    return redirect(url_for('index'))


@app.route('/refresh')
@login_required
def refresh():
    refresh_token = session.get('refresh_token')
    if not refresh_token:
        return 'No refresh token available', 400
    
    token_data = {
        'grant_type': 'refresh_token',
        'refresh_token': refresh_token,
        'client_id': OIDC_CONFIG['client_id'],
        'client_secret': OIDC_CONFIG['client_secret']
    }
    
    try:
        token_response = requests.post(
            OIDC_CONFIG['token_endpoint'],
            data=token_data,
            headers={'Content-Type': 'application/x-www-form-urlencoded'}
        )
        token_response.raise_for_status()
        tokens = token_response.json()
        
        # Update tokens in session
        session['access_token'] = tokens.get('access_token')
        if tokens.get('refresh_token'):
            session['refresh_token'] = tokens.get('refresh_token')
        
        return jsonify({'message': 'Tokens refreshed successfully'})
    
    except requests.RequestException as e:
        return f'Token refresh failed: {str(e)}', 500


if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)